import React, { useState, useEffect } from 'react';
import axios from 'axios';
import AddProduct from './components/AddProduct';
import ProductList from './components/ProductList';

const API = '/api/products';

function App() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [toast, setToast] = useState('');

  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(''), 3000);
  };

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const res = await axios.get(API);
      setProducts(res.data);
    } catch (err) {
      showToast('❌ Failed to load products');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchProducts(); }, []);

  const handleAdd = async (productData) => {
    const res = await axios.post(API, productData);
    setProducts([res.data, ...products]);
    showToast('✅ Product added successfully!');
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this product?')) return;
    try {
      await axios.delete(`${API}/${id}`);
      setProducts(products.filter((p) => p._id !== id));
      showToast('🗑 Product deleted.');
    } catch (err) {
      showToast('❌ Failed to delete product.');
    }
  };

  const totalValue = products.reduce((sum, p) => sum + p.price * p.quantity, 0);

  return (
    <div style={styles.app}>
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <div>
            <h1 style={styles.logo}>📋 Inventory Manager</h1>
            <p style={styles.subtitle}>MERN Stack — Manage your products with ease</p>
          </div>
          <div style={styles.stats}>
            <div style={styles.stat}>
              <span style={styles.statNum}>{products.length}</span>
              <span style={styles.statLabel}>Products</span>
            </div>
            <div style={styles.stat}>
              <span style={styles.statNum}>${totalValue.toFixed(2)}</span>
              <span style={styles.statLabel}>Total Value</span>
            </div>
          </div>
        </div>
      </header>

      <main style={styles.main}>
        <AddProduct onAdd={handleAdd} />
        <ProductList products={products} onDelete={handleDelete} loading={loading} />
      </main>

      {toast && <div style={styles.toast}>{toast}</div>}
    </div>
  );
}

const styles = {
  app: { minHeight: '100vh', background: '#f0f2f5' },
  header: { background: 'linear-gradient(135deg, #4f46e5, #7c3aed)', color: '#fff', padding: '24px 0', boxShadow: '0 4px 16px rgba(79,70,229,0.3)' },
  headerInner: { maxWidth: '960px', margin: '0 auto', padding: '0 24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  logo: { fontSize: '1.6rem', fontWeight: 800 },
  subtitle: { fontSize: '0.9rem', opacity: 0.8, marginTop: '4px' },
  stats: { display: 'flex', gap: '32px' },
  stat: { textAlign: 'center' },
  statNum: { display: 'block', fontSize: '1.5rem', fontWeight: 800 },
  statLabel: { fontSize: '0.8rem', opacity: 0.8 },
  main: { maxWidth: '960px', margin: '0 auto', padding: '32px 24px' },
  toast: {
    position: 'fixed', bottom: '24px', right: '24px',
    background: '#1a1a2e', color: '#fff', padding: '12px 24px',
    borderRadius: '10px', boxShadow: '0 4px 16px rgba(0,0,0,0.2)',
    fontSize: '0.95rem', fontWeight: 500, zIndex: 999,
  },
};

export default App;
